ON CONFLICT DO NOTHING;

-- Exercícios essenciais clássicos
  -- PEITO
  ('Supino Reto com Barra', 'peito', 'intermediario', 'Deite no banco plano com pegada média (ângulo de 90 graus no meio do movimento entre antebraço e braço). Retire a barra do rack e mantenha-a estendida sobre o peito. Inspire e desça a barra lentamente até tocar o peito, depois empurre de volta à extensão.', 'peitoral maior, tríceps, deltoide anterior', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Bench_Press_-_Medium_Grip/0.jpg'),
  ('Supino Inclinado com Barra', 'peito', 'intermediario', 'Deite no banco inclinado com pegada média. Retire a barra do rack e mantenha-a estendida. Inspire e desça lentamente até a barra tocar a parte superior do peito. Empurre de volta à posição inicial.', 'peitoral maior (porção clavicular), tríceps, deltoide anterior', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Incline_Bench_Press/0.jpg'),
  ('Supino Reto com Halteres', 'peito', 'intermediario', 'Deite no banco plano com um haltere em cada mão na altura do peito. Empurre os halteres para cima convergindo levemente no topo. Abaixe com controle até sentir o alongamento no peito.', 'peitoral maior, tríceps, deltoide anterior', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Bench_Press/0.jpg'),
  ('Supino Inclinado com Halteres', 'peito', 'intermediario', 'No banco inclinado (30-45 graus), pressione os halteres de baixo para cima. Os cotovelos devem fazer um ângulo de 45 graus com o corpo.', 'peitoral maior (porção clavicular), tríceps, deltoide anterior', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Incline_Bench_Press_/0.jpg'),
  ('Crucifixo com Halteres', 'peito', 'intermediario', 'Deite no banco plano com halteres acima do peito, cotovelos levemente flexionados. Abra os braços em arco até sentir o alongamento no peito e retorne ao ponto inicial.', 'peitoral maior, deltoide anterior', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Flyes/0.jpg'),
  ('Crossover no Cabo', 'peito', 'intermediario', 'Posicione as roldanas em cima. De pé no centro, puxe os cabos para frente e abaixo convergindo as mãos na frente do corpo. Controle o retorno.', 'peitoral maior, deltoide anterior', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Crossover/0.jpg'),
  ('Flexão de Braço', 'peito', 'iniciante', 'Em posição de prancha alta, com as mãos levemente mais largas que os ombros, desça o peito até próximo ao chão dobrando os cotovelos. Empurre de volta estendendo os braços.', 'peitoral maior, tríceps, deltoide anterior', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Up/0.jpg'),
  ('Supino Declinado com Barra', 'peito', 'intermediario', 'No banco declinado, segure a barra com pegada levemente mais larga que os ombros. Desça até a parte inferior do peito e empurre de volta.', 'peitoral maior (porção esternal), tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Decline_Bench_Press/0.jpg'),

  -- COSTAS
  ('Levantamento Terra', 'costas', 'avancado', 'Com os pés na largura dos quadris, segure a barra com pegada dupla pronada ou alternada. Mantenha a coluna neutra, empurre o chão com os pés e estenda os quadris e joelhos simultaneamente até a posição vertical.', 'lombar, glúteos, isquiotibiais, trapézio, latíssimo do dorso', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Deadlift/0.jpg'),
  ('Remada Curvada com Barra', 'costas', 'avancado', 'Segure a barra com pegada pronada. Com os joelhos levemente dobrados, incline o tronco à frente mantendo as costas retas até quase paralelo ao chão. Puxe a barra em direção ao abdômen mantendo os cotovelos próximos ao corpo e retraindo as escápulas no topo.', 'latíssimo do dorso, dorsais médios, romboides, bíceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Bent_Over_Row/0.jpg'),
  ('Puxada Frontal', 'costas', 'iniciante', 'Sentado na máquina de puxada, segure a barra com pegada mais larga que os ombros. Puxe a barra até a clavícula enquanto abre o peito e inclina levemente o tronco. Retorne de forma controlada.', 'latíssimo do dorso, bíceps, romboides', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wide-Grip_Lat_Pulldown/0.jpg'),
  ('Barra Fixa', 'costas', 'avancado', 'Segure a barra com pegada pronada mais larga que os ombros. A partir de braços estendidos, puxe o corpo até o queixo ultrapassar a barra. Desça com controle.', 'latíssimo do dorso, bíceps, romboides', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wide-Grip_Barbell_Pull-Up/0.jpg'),
  ('Remada Sentada no Cabo', 'costas', 'iniciante', 'Sentado na máquina de remada, com as costas retas, puxe a pegada em direção ao abdômen. Contraia as escápulas no final e retorne controlando o peso.', 'latíssimo do dorso, dorsais médios, bíceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Cable_Rows/0.jpg'),
  ('Remada Unilateral com Haltere', 'costas', 'iniciante', 'Com um joelho e mão no banco para suporte, puxe o haltere com a outra mão em direção ao quadril. Mantenha o cotovelo próximo ao corpo e a coluna paralela ao chão.', 'latíssimo do dorso, dorsais médios, bíceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_One-Arm_Row/0.jpg'),
  ('Levantamento Terra Romeno', 'costas', 'intermediario', 'De pé com a barra na frente das coxas, incline o torso à frente mantendo as costas retas e os joelhos levemente flexionados. Desça até sentir o alongamento nos isquiotibiais e retorne.', 'isquiotibiais, glúteos, lombar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Romanian_Deadlift/0.jpg'),
  ('Puxada na Frente com Triângulo', 'costas', 'iniciante', 'Usando a pegada em triângulo (neutra), puxe o cabo até o peito. Este ângulo ativa mais o latíssimo e reduz a tensão nos ombros.', 'latíssimo do dorso, bíceps, romboides', NULL),
  ('Serrote com Haltere', 'costas', 'iniciante', 'Apoie o joelho e mão ipsilateral no banco. Puxe o haltere do outro lado em direção ao quadril realizando o movimento de remada. Mantenha o cotovelo colado ao corpo.', 'latíssimo do dorso, dorsais médios, bíceps', NULL),

  -- OMBROS
  ('Desenvolvimento com Barra', 'ombro', 'intermediario', 'Sente-se num banco com encosto dentro de um rack. Posicione a barra na altura da cabeça com pegada pronada. Retire do rack segurando na altura dos ombros levemente à frente. Pressione para cima até a extensão completa dos cotovelos e desça de forma controlada.', 'deltoide, tríceps, trapézio', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Seated_Behind_Neck_Press/0.jpg'),
  ('Desenvolvimento com Halteres', 'ombro', 'iniciante', 'Sentado com os halteres na altura dos ombros e palmas voltadas para a frente, pressione-os acima da cabeça convergindo levemente no topo. Retorne com controle.', 'deltoide, tríceps, trapézio', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Shoulder_Press/0.jpg'),
  ('Elevação Lateral com Halteres', 'ombro', 'iniciante', 'Em pé com halteres ao lado do corpo, eleve os braços lateralmente até a altura dos ombros com os cotovelos levemente flexionados. Controle a descida.', 'deltoide medial', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Lateral_Raise/0.jpg'),
  ('Elevação Frontal com Halteres', 'ombro', 'iniciante', 'Em pé com halteres à frente das coxas, eleve um braço de cada vez (ou ambos) até a altura dos ombros. Mantenha o cotovelo levemente flexionado.', 'deltoide anterior', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Front_Raise/0.jpg'),
  ('Crucifixo Inverso com Halteres', 'ombro', 'iniciante', 'Com o torso inclinado à frente e halteres pendentes, abra os braços lateralmente contraindo o deltoide posterior e os romboides. Controle a descida.', 'deltoide posterior, romboides, trapézio médio', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_Dumbbell_Rear_Delt_Row_with_Head_on_Bench/0.jpg'),
  ('Remada Alta com Barra', 'ombro', 'intermediario', 'Com pegada estreita na barra, puxe-a verticalmente até o queixo. Os cotovelos devem ficar acima das mãos durante o movimento.', 'trapézio, deltoide medial, bíceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Upright_Row/0.jpg'),
  ('Face Pull no Cabo', 'ombro', 'iniciante', 'Com a roldana na altura do rosto, puxe a corda até o rosto separando as mãos no final. Excelente para saúde do manguito rotador.', 'deltoide posterior, romboides, trapézio médio', NULL),

  -- BÍCEPS
  ('Rosca Bíceps com Barra', 'biceps', 'iniciante', 'Em pé com o torso ereto, segure a barra na largura dos ombros com pegada supinada (palmas para frente) e cotovelos próximos ao tronco. Flexione os cotovelos elevando a barra em direção aos ombros, sem mover os braços. Somente os antebraços se movem.', 'bíceps braquial, braquial', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Curl/0.jpg'),
  ('Rosca Bíceps com Halteres', 'biceps', 'iniciante', 'Em pé ou sentado, com halteres ao lado do corpo, flexione os cotovelos alternando ou simultaneamente. Gire o pulso supinando ao longo do movimento.', 'bíceps braquial, braquial', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Alternate_Bicep_Curl/0.jpg'),
  ('Rosca Scott (Preacher Curl)', 'biceps', 'iniciante', 'Apoie o tríceps no banco Scott e flexione o cotovelo elevando a barra ou haltere. Evite o impulso final e controle o retorno enfatizando o alongamento.', 'bíceps braquial (porção curta)', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Preacher_Curl/0.jpg'),
  ('Rosca Concentrada', 'biceps', 'iniciante', 'Sentado com o cotovelo apoiado na parte interna da coxa, realize a rosca com um haltere. Movimento isolado para o pico do bíceps.', 'bíceps braquial', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Concentration_Curls/0.jpg'),
  ('Rosca no Cabo', 'biceps', 'iniciante', 'Com a roldana baixa, segure a barra reta ou EZ e realize a rosca. O cabo mantém tensão constante ao longo de todo o movimento.', 'bíceps braquial, braquial', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Hammer_Curls_-_Rope_Attachment/0.jpg'),

  -- TRÍCEPS
  ('Tríceps Pulley (Pushdown)', 'triceps', 'iniciante', 'Com a roldana alta, segure a barra reta ou V com as mãos na largura dos ombros. Empurre a barra para baixo estendendo os cotovelos até bloqueio. Mantenha os cotovelos fixos ao lado do corpo.', 'tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Triceps_Pushdown/0.jpg'),
  ('Tríceps Testa (Skull Crusher)', 'triceps', 'intermediario', 'Deitado no banco com a barra acima, desça a barra em direção à testa flexionando apenas os cotovelos. Estenda de volta contraindo o tríceps. Cotovelos apontando para o teto.', 'tríceps (todas as porções)', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_JM_Press/0.jpg'),
  ('French Press (Tríceps com Haltere)', 'triceps', 'iniciante', 'Sentado ou deitado, segure um haltere com as duas mãos acima da cabeça. Flexione os cotovelos abaixando o haltere atrás da cabeça e estenda de volta.', 'tríceps (porção longa)', NULL),
  ('Mergulho em Paralelas', 'triceps', 'intermediario', 'Nas barras paralelas com o corpo ereto, desça flexionando os cotovelos até 90 graus. Empurre de volta à extensão completa. Para focar no tríceps, mantenha o tronco vertical.', 'tríceps, peitoral, deltoide anterior', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chest_Dip/0.jpg'),
  ('Extensão de Tríceps com Corda', 'triceps', 'iniciante', 'Com a roldana alta e pegada na corda, empurre para baixo separando as mãos no final do movimento. Maior amplitude que a barra reta.', 'tríceps', NULL),

  -- PERNAS
  ('Agachamento com Barra', 'pernas', 'avancado', 'Execute dentro de um rack. Ajuste a barra abaixo da linha dos ombros e apoie no trapézio. Retire do rack. Com os pés na largura dos ombros e levemente apontados para fora, agache até as coxas ficarem paralelas ao chão mantendo o peito alto e a coluna neutra. Empurre pelos calcanhares para subir.', 'quadríceps, glúteos, isquiotibiais, lombar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Full_Squat/0.jpg'),
  ('Leg Press 45°', 'pernas', 'iniciante', 'Na máquina de leg press, posicione os pés na plataforma na largura dos ombros. Desça o peso com controle até os joelhos formarem 90 graus e empurre de volta sem travar os joelhos.', 'quadríceps, glúteos, isquiotibiais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Press/0.jpg'),
  ('Extensão de Pernas', 'pernas', 'iniciante', 'Sentado na cadeira extensora, estenda os joelhos até a posição horizontal contraindo o quadríceps. Retorne controladamente sem deixar o peso bater.', 'quadríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Extensions/0.jpg'),
  ('Rosca Femoral (Leg Curl)', 'pernas', 'iniciante', 'Deitado na mesa de rosca femoral, flexione os joelhos em direção ao glúteo. Contraia os isquiotibiais no topo e retorne de forma controlada.', 'isquiotibiais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Leg_Curls/0.jpg'),
  ('Avanço com Halteres', 'pernas', 'iniciante', 'Em pé com halteres nas mãos, dê um passo à frente e desça o joelho traseiro em direção ao chão. Empurre pelo calcanhar da perna da frente para retornar.', 'quadríceps, glúteos, isquiotibiais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Lunges/0.jpg'),
  ('Hip Thrust com Barra', 'pernas', 'intermediario', 'Apoie as escápulas no banco e coloque a barra sobre os quadris. Com os pés no chão e joelhos a 90 graus, empurre os quadris para cima contraindo os glúteos. Mantenha o queixo para o peito.', 'glúteos, isquiotibiais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Hip_Thrust/0.jpg'),
  ('Panturrilha em Pé', 'pernas', 'iniciante', 'Na máquina de panturrilha ou com halteres, eleve-se na ponta dos pés contraindo a panturrilha no topo. Desça até sentir o alongamento do sóleo e gastrocnêmio.', 'gastrocnêmio, sóleo', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Calf_Raises_-_Donkey/0.jpg'),
  ('Agachamento Goblet', 'pernas', 'iniciante', 'Segure um kettlebell ou haltere com as duas mãos na frente do peito. Agache mantendo o torso ereto, os joelhos apontando para fora e os calcanhares no chão.', 'quadríceps, glúteos, core', NULL),
  ('Stiff (Terra com Pernas Retas)', 'pernas', 'intermediario', 'Com a barra na frente das coxas e as pernas praticamente estendidas, incline o torso à frente descendo a barra ao longo das pernas. Sinta o alongamento máximo nos isquiotibiais e retorne.', 'isquiotibiais, glúteos, lombar', NULL),

  -- ABDÔMEN
  ('Abdominal Crunch', 'abdomen', 'iniciante', 'Deitado de costas com os joelhos flexionados e pés no chão, eleve apenas os ombros do chão contraindo o abdômen. Evite puxar pelo pescoço. Retorne com controle.', 'reto abdominal', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Crunch/0.jpg'),
  ('Prancha (Plank)', 'abdomen', 'iniciante', 'Apoiado nos antebraços e pontas dos pés, mantenha o corpo alinhado da cabeça aos calcanhares. Contraia o abdômen e glúteos. Evite deixar o quadril cair ou elevar.', 'reto abdominal, transverso, oblíquos', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plank/0.jpg'),
  ('Elevação de Pernas', 'abdomen', 'intermediario', 'Deitado com as mãos sob os glúteos, eleve as pernas estendidas até 90 graus contraindo o abdômen inferior. Desça sem tocar o chão para manter a tensão.', 'reto abdominal (porção inferior)', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Leg_Raises/0.jpg'),
  ('Abdominal com Roda (Ab Wheel)', 'abdomen', 'avancado', 'De joelhos com a roda na frente, role para a frente estendendo o corpo próximo ao chão. Contraia o abdômen para retornar. Mantenha a lombar neutra durante todo o movimento.', 'reto abdominal, oblíquos, lombar', NULL),
  ('Torção Russa', 'abdomen', 'iniciante', 'Sentado com os pés levemente elevados e o torso inclinado a 45 graus, gire o tronco de um lado para o outro. Pode ser realizado com ou sem peso.', 'oblíquos, reto abdominal', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Russian_Twist/0.jpg')
ON CONFLICT DO NOTHING;
