INSERT INTO exercises (name, muscle_group, difficulty, description, muscles_worked, image_url)
VALUES
  ('Abdominal 3/4', 'abdomen', 'iniciante', 'Deite no chão e fixe os pés. Joelhos dobrados, mãos atrás ou ao lado da cabeça. Suba o tronco até aproximadamente três quartos do movimento completo, contraindo o abdômen, e retorne com controle.', 'abdominais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/3_4_Sit-Up/0.jpg'),
  ('Abdominal na Máquina', 'abdomen', 'intermediario', 'Selecione uma carga leve e sente-se na máquina com os pés sob os suportes e as mãos nas alças. Os cotovelos devem formar 90 graus. Eleve as pernas enquanto faz a flexão do tronco, expirando durante o movimento. Use cadência lenta e controlada, concentrando-se no abdômen.', 'abdominais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Ab_Crunch_Machine/0.jpg'),
  ('Roda Abdominal', 'abdomen', 'intermediario', 'Segure a roda com as duas mãos e ajoelhe-se no chão. Posicione a roda à sua frente como em uma posição de prancha de joelhos. Essa é a posição inicial. Role para frente estendendo o corpo e retorne contraindo o abdômen.', 'abdominais, ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Ab_Roller/0.jpg'),
  ('Advanced Kettlebell Windmill', 'abdomen', 'intermediario', 'Suba um kettlebell com um braço estendido acima da cabeça. Mantendo-o travado, empurre o quadril na direção do peso. Deixe o braço livre atrás das costas e gire os pés 45 graus. Incline o tronco lateralmente até tocar o chão com a mão livre, mantendo os olhos no kettlebell.', 'abdominais, glúteos, isquiotibiais, ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Advanced_Kettlebell_Windmill/0.jpg'),
  ('Bicicleta no Ar (Abdominal Alternado)', 'abdomen', 'iniciante', 'Deite de costas com a lombar pressionada no chão. Coloque as mãos ao lado da cabeça sem forçar o pescoço. Eleve os ombros em posição de crunch. Traga os joelhos a 90 graus com as pernas paralelas ao chão. Alterne levando o cotovelo direito ao joelho esquerdo e vice-versa, como se pedalasse.', 'abdominais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Air_Bike/0.jpg'),
  ('Rosca Martelo Alternada', 'biceps', 'iniciante', 'Em pé com o torso ereto, segure um haltere em cada mão com os braços estendidos e as palmas voltadas para o corpo. Mantenha os cotovelos próximos ao tronco. Flexione um cotovelo de cada vez elevando o haltere até a altura do ombro, alternando os lados.', 'bíceps, antebraço', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternate_Hammer_Curl/0.jpg'),
  ('Alternate Heel Touchers', 'abdomen', 'iniciante', 'Deite no chão com os joelhos dobrados e os pés afastados cerca de 45-60 cm. Os braços esticados ao lado do corpo. Faça uma flexão lateral do tronco tocando o calcanhar direito com a mão direita, segure um segundo e alterne para o lado esquerdo. Expire ao realizar o movimento.', 'abdominais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternate_Heel_Touchers/0.jpg'),
  ('Rosca Bíceps Inclinada Alternada', 'biceps', 'iniciante', 'Sente-se num banco inclinado com um haltere em cada mão pendendo ao lado do corpo, cotovelos próximos ao tronco. Alternando os lados, flexione o cotovelo enquanto supina o pulso (palma para cima) ao longo do movimento. Contraia o bíceps no topo e desça com controle.', 'bíceps, antebraço', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternate_Incline_Dumbbell_Curl/0.jpg'),
  ('Desenvolvimento no Cabo Alternado', 'ombro', 'iniciante', 'Posicione as roldanas na base da torre e selecione o peso adequado. Segure os cabos na altura dos ombros com as palmas voltadas para frente. Pressione um braço de cada vez acima da cabeça estendendo o cotovelo, alternando os lados.', 'ombros, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Cable_Shoulder_Press/0.jpg'),
  ('Elevação Deltóide Alternada', 'ombro', 'iniciante', 'Em pé, segure um par de halteres ao lado do corpo. Mantendo os cotovelos levemente flexionados, eleve alternadamente cada braço à frente até a altura dos ombros, sem balançar o corpo.', 'ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Deltoid_Raise/0.jpg'),
  ('Supino no Chão Alternado com Kettlebell', 'peito', 'iniciante', 'Deite no chão com dois kettlebells ao lado dos ombros. Posicione-os sobre o peito um de cada vez, com a pegada no cabo e palmas voltadas para frente. Pressione alternadamente um kettlebell enquanto mantém o outro estático.', 'peitoral, abdominais, ombros, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Floor_Press/0.jpg'),
  ('Alternating Hang Clean', 'pernas', 'intermediario', 'Posicione dois kettlebells entre os pés. Na posição inicial, empurre o quadril para trás e olhe para frente. Suba um kettlebell ao ombro enquanto mantém o outro pendurado. Estenda as pernas e quadril para puxar o kettlebell ao ombro, girando o pulso ao longo do movimento.', 'isquiotibiais, bíceps, panturrilha, antebraço, glúteos, lombar, trapézio', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Hang_Clean/0.jpg'),
  ('Desenvolvimento com Kettlebell Alternado', 'ombro', 'intermediario', 'Suba dois kettlebells até os ombros. Pressione um diretamente acima da cabeça estendendo o cotovelo e girando o pulso (palma para frente), enquanto mantém o outro estático no ombro. Alterne os lados.', 'ombros, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Kettlebell_Press/0.jpg'),
  ('Remada com Kettlebell Alternada', 'costas', 'intermediario', 'Posicione dois kettlebells à frente dos pés. Com os joelhos levemente dobrados e o quadril empurrado para trás, segure ambos pelos cabos. Puxe um kettlebell do chão enquanto mantém o outro pendurado, retraindo a escápula do lado trabalhado e flexionando o cotovelo em direção ao abdômen.', 'dorsais médios, bíceps, latíssimo do dorso', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Kettlebell_Row/0.jpg'),
  ('Remada Renegade Alternada', 'costas', 'avancado', 'Posicione dois kettlebells no chão na largura dos ombros. Assuma a posição de prancha alta apoiado nas alças dos kettlebells. Mantenha os pés afastados para equilíbrio. Pressione um kettlebell no chão enquanto remada o outro, retraindo a escápula e puxando até o lado do corpo.', 'dorsais médios, abdominais, bíceps, peitoral, latíssimo do dorso, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Renegade_Row/0.jpg'),
  ('Desenvolvimento Arnold', 'ombro', 'intermediario', 'Sente-se num banco com encosto segurando dois halteres na frente do peito, palmas voltadas para você e cotovelos dobrados. Pressione os halteres para cima enquanto gira as palmas para frente ao longo do movimento, até a extensão completa dos braços. Retorne revertendo a rotação.', 'ombros, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Arnold_Dumbbell_Press/0.jpg'),
  ('Crucifixo Circular com Halteres', 'peito', 'intermediario', 'Deite no banco plano com os halteres estendidos ao lado das coxas, palmas para cima e cotovelos levemente flexionados. Faça um semicírculo com os braços paralelos ao chão, deslocando os halteres da posição inicial até acima da cabeça. Mantenha os braços paralelos ao chão durante todo o arco.', 'peitoral, ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Around_The_Worlds/0.jpg'),
  ('Crucifixo Inverso com Elástico', 'ombro', 'iniciante', 'Enrole o elástico num suporte fixo como um rack. Segure as alças e dê um passo para trás até sentir tensão no elástico. Realizando um crucifixo reverso, abra os braços lateralmente até a altura dos ombros contraindo o deltoide posterior.', 'ombros, dorsais médios, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Back_Flyes_-_With_Bands/0.jpg'),
  ('Balance Board', 'pernas', 'iniciante', 'Posicione a prancha de equilíbrio à sua frente. Suba sobre ela e tente se equilibrar mantendo o controle do centro do corpo.', 'panturrilha, isquiotibiais, quadríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Balance_Board/0.jpg'),
  ('Barra Fixa Assistida com Elástico', 'costas', 'iniciante', 'Enrole o elástico no centro da barra de tração. Puxe a ponta do elástico para baixo e apoie um joelho dobrado no laço. Segure a barra com pegada média a larga. Puxe o corpo para cima até o queixo ultrapassar a barra, usando o elástico como suporte.', 'latíssimo do dorso, abdominais, antebraço, dorsais médios', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Assisted_Pull-Up/0.jpg'),
  ('Bom Dia com Elástico', 'pernas', 'intermediario', 'Pise em uma extremidade de um elástico longo e dobre os joelhos levemente. Encaixe a outra extremidade atrás do pescoço. Mantendo as pernas quase retas, incline o tronco à frente com a coluna reta e retorne à posição vertical através da extensão dos quadris.', 'isquiotibiais, glúteos, lombar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Good_Morning/0.jpg'),
  ('Band Good Morning (Pull Through)', 'pernas', 'intermediario', 'Prenda o elástico num suporte. De costas para o suporte e afastado o suficiente para gerar tensão, encaixe o elástico atrás do pescoço. Incline o tronco à frente empurrando o quadril para trás ao máximo, mantendo as costas retas e os joelhos levemente dobrados, até aproximadamente 90 graus.', 'isquiotibiais, glúteos, lombar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Good_Morning_Pull_Through/0.jpg'),
  ('Band Hip Adductions', 'pernas', 'iniciante', 'Prenda o elástico num suporte fixo. Fique de lado ao suporte com o pé mais distante passando pelo elástico (na altura do tornozelo). Puxe a perna em direção à linha média do corpo, contraindo os adutores.', 'adutores', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Hip_Adductions/0.jpg'),
  ('Abertura com Elástico', 'ombro', 'iniciante', 'Com os braços estendidos à frente segurando o elástico com as duas mãos, inicie o movimento abrindo os braços lateralmente realizando um crucifixo reverso. Mantenha os cotovelos levemente dobrados durante toda a amplitude.', 'ombros, dorsais médios, trapézio', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Pull_Apart/0.jpg'),
  ('Testa com Elástico', 'triceps', 'iniciante', 'Prenda o elástico na base do rack ou banco. Deite de forma que o elástico fique alinhado com sua cabeça. Segure o elástico e eleve os cotovelos para que o braço fique perpendicular ao chão. Com os cotovelos dobrados e o elástico acima da cabeça, estenda os cotovelos contraindo o tríceps.', 'tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Skull_Crusher/0.jpg'),
  ('Roda Abdominal com Barra', 'abdomen', 'intermediario', 'Assuma a posição de prancha alta segurando uma barra olímpica (com pequenos anilhos) no lugar das mãos. Mantendo um leve arco nas costas, eleve o quadril e role a barra em direção aos pés expirando. Os glúteos devem subir, o abdômen se contrair e a postura das costas ser mantida.', 'abdominais, lombar, ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Ab_Rollout/0.jpg'),
  ('Roda Abdominal com Barra (Joelhos)', 'abdomen', 'avancado', 'Segure uma barra olímpica com pequenos anilhos e ajoelhe-se no chão. Posicione a barra à sua frente como em uma prancha de joelhos. Role para frente estendendo o corpo próximo ao chão e retorne contraindo o abdômen e a lombar.', 'abdominais, lombar, ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Ab_Rollout_-_On_Knees/0.jpg'),
  ('Supino Reto com Barra', 'peito', 'iniciante', 'Deite no banco plano com pegada média (ângulo de 90 graus no meio do movimento entre antebraço e braço). Retire a barra do rack e mantenha-a estendida sobre o peito. Inspire e desça a barra lentamente até tocar o peito, depois empurre de volta à extensão.', 'peitoral, ombros, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Bench_Press_-_Medium_Grip/0.jpg'),
  ('Rosca Bíceps com Barra', 'biceps', 'iniciante', 'Em pé com o torso ereto, segure a barra na largura dos ombros com pegada supinada (palmas para frente) e cotovelos próximos ao tronco. Flexione os cotovelos elevando a barra em direção aos ombros, sem mover os braços. Somente os antebraços se movem.', 'bíceps, antebraço', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Curl/0.jpg'),
  ('Rosca Bíceps com Barra no Banco Inclinado', 'biceps', 'iniciante', 'Apoie-se num banco inclinado de bruços, com os braços segurando a barra pendentes em linha horizontal. Essa é a posição inicial. Mantenha os braços superiores estacionários e flexione os cotovelos elevando o peso o máximo possível, contraindo os bíceps. Somente os antebraços devem se mover.', 'bíceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Curls_Lying_Against_An_Incline/0.jpg'),
  ('Levantamento Terra com Barra', 'costas', 'avancado', 'Fique em frente à barra carregada. Mantendo as costas o mais retas possível, dobre os joelhos e incline o torso para frente segurando a barra com pegada pronada na largura dos ombros. Empurre o chão com os pés estendendo joelhos e quadril simultaneamente até ficar em pé, com a barra próxima ao corpo.', 'lombar, panturrilha, antebraço, glúteos, isquiotibiais, latíssimo do dorso, dorsais médios, quadríceps, trapézio', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Deadlift/0.jpg'),
  ('Agachamento Completo com Barra', 'pernas', 'avancado', 'Execute dentro de um rack por segurança. Ajuste a barra abaixo da altura dos ombros, passe por baixo e apoie-a levemente abaixo do pescoço no trapézio. Retire do rack empurrando com as pernas. Desça até a profundidade máxima mantendo o peito alto e os joelhos alinhados com os pés, depois suba.', 'quadríceps, panturrilha, glúteos, isquiotibiais, lombar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Full_Squat/0.jpg'),
  ('Ponte Glúteo com Barra', 'pernas', 'intermediario', 'Sente-se no chão com a barra sobre as pernas. Role a barra diretamente sobre os quadris e deite de costas. Empurre pelos calcanhares estendendo os quadris verticalmente. O peso deve ser suportado pelas escápulas e calcanhares dos pés.', 'glúteos, panturrilha, isquiotibiais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Glute_Bridge/0.jpg'),
  ('Supino Guilhotina com Barra', 'peito', 'avancado', 'Usando pegada média, retire a barra do rack e mantenha-a estendida sobre o pescoço. Desça lentamente até aproximadamente 2-3 cm do pescoço. Empurre de volta à extensão. Exige atenção especial à segurança.', 'peitoral, ombros, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Guillotine_Bench_Press/0.jpg'),
  ('Agachamento Hack com Barra', 'pernas', 'intermediario', 'Em pé segurando a barra atrás do corpo com pegada pronada na largura dos ombros. Mantenha a cabeça e olhos para cima e as costas retas. Agache até as coxas ficarem paralelas ao chão, inspire na descida e expire na subida.', 'quadríceps, panturrilha, antebraço, isquiotibiais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Hack_Squat/0.jpg'),
  ('Elevação de Quadril com Barra (Hip Thrust)', 'pernas', 'intermediario', 'Sente-se no chão com um banco atrás e a barra sobre as pernas. Role a barra sobre os quadris e incline as escápulas no topo do banco. Empurre os quadris para cima pelo impulso dos calcanhares até a extensão completa, contraindo os glúteos no topo.', 'glúteos, panturrilha, isquiotibiais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Hip_Thrust/0.jpg'),
  ('Supino Inclinado com Barra', 'peito', 'iniciante', 'Deite no banco inclinado com pegada média. Retire a barra do rack e mantenha-a estendida. Inspire e desça lentamente até a barra tocar a parte superior do peito. Empurre de volta à posição inicial.', 'peitoral, ombros, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Incline_Bench_Press_-_Medium_Grip/0.jpg'),
  ('Elevação Frontal no Banco Inclinado com Barra', 'ombro', 'iniciante', 'Deite num banco inclinado e segure a barra com pegada levemente mais larga que os ombros. Mantendo os braços estendidos, eleve a barra protraindo as escápulas e levantando os ombros do banco enquanto expira.', 'ombros, peitoral', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Incline_Shoulder_Raise/0.jpg'),
  ('Avanço com Barra', 'pernas', 'intermediario', 'Execute dentro de um rack. Apoie a barra no trapézio, retire do rack e dê um passo à frente com uma perna. Desça o joelho traseiro em direção ao chão mantendo o torso ereto e o joelho da frente alinhado com o pé. Empurre de volta e alterne as pernas.', 'quadríceps, panturrilha, glúteos, isquiotibiais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Lunge/0.jpg'),
  ('Remada Alta para Deltóide Posterior com Barra', 'ombro', 'iniciante', 'Em pé segurando a barra com pegada larga pronada. Dobre levemente os joelhos e incline o torso para frente mantendo as costas retas. Abra os cotovelos para os lados formando a letra T com o tronco e braços, puxando a barra em direção ao tronco.', 'ombros, bíceps, latíssimo do dorso, dorsais médios', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Rear_Delt_Row/0.jpg'),
  ('Roda Abdominal com Barra no Banco', 'abdomen', 'intermediario', 'Coloque a barra carregada próxima ao final de um banco. Ajoelhe-se sobre o banco com os joelhos, segure a barra com pegada média ou estreita. Estenda os quadris rolando a barra para frente e flexione os ombros para levar a barra acima da cabeça. Mantenha os braços estendidos durante todo o movimento.', 'abdominais, glúteos, isquiotibiais, latíssimo do dorso, ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Rollout_from_Bench/0.jpg'),
  ('Panturrilha Sentado com Barra', 'pernas', 'iniciante', 'Coloque um step ou plataforma a cerca de 30 cm de um banco. Sente-se e posicione a bola dos pés no step. Execute elevações na ponta dos pés contraindo a panturrilha no topo e alongando na descida.', 'panturrilha', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Seated_Calf_Raise/0.jpg'),
  ('Desenvolvimento com Barra', 'ombro', 'intermediario', 'Sente-se num banco com encosto dentro de um rack. Posicione a barra na altura da cabeça com pegada pronada. Retire do rack segurando na altura dos ombros levemente à frente. Pressione para cima até a extensão completa dos cotovelos e desça de forma controlada.', 'ombros, peitoral, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Shoulder_Press/0.jpg'),
  ('Encolhimento de Ombros com Barra', 'costas', 'iniciante', 'Em pé com os pés na largura dos ombros, segure a barra à frente com pegada pronada levemente mais larga que os ombros. Eleve os ombros o máximo possível contraindo o trapézio por um segundo. Não tente mover a barra com os bíceps.', 'trapézio', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Shrug/0.jpg'),
  ('Encolhimento de Ombros com Barra por Trás', 'costas', 'iniciante', 'Em pé segure a barra atrás do corpo com pegada pronada levemente mais larga que os ombros. Eleve os ombros contraindo o trapézio por um segundo e retorne com controle. Os braços devem permanecer estendidos.', 'trapézio, antebraço, dorsais médios', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Shrug_Behind_The_Back/0.jpg'),
  ('Flexão Lateral com Barra', 'abdomen', 'iniciante', 'Em pé com a barra apoiada no trapézio e pés na largura dos ombros. Mantendo as costas retas e a cabeça elevada, incline o tronco lateralmente para a direita o máximo possível. Segure um segundo e retorne. Alterne os lados.', 'abdominais, lombar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Side_Bend/0.jpg'),
  ('Agachamento Lateral com Barra', 'pernas', 'iniciante', 'Em pé com a barra no trapézio, pés bem afastados e o pé da perna líder apontado para o lado. Desça em direção ao pé angulado dobrando o joelho e quadril dessa perna enquanto mantém a outra perna quase reta. Inspire na descida.', 'quadríceps, panturrilha, isquiotibiais, lombar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Side_Split_Squat/0.jpg'),
  ('Agachamento com Barra', 'pernas', 'iniciante', 'Execute dentro de um rack. Ajuste a barra abaixo da linha dos ombros e apoie no trapézio. Retire do rack. Com os pés na largura dos ombros e levemente apontados para fora, agache até as coxas ficarem paralelas ao chão mantendo o peito alto e a coluna neutra. Empurre pelos calcanhares para subir.', 'quadríceps, panturrilha, glúteos, isquiotibiais, lombar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Squat/0.jpg'),
  ('Agachamento com Barra até o Banco', 'pernas', 'avancado', 'Execute dentro de um rack com um banco posicionado atrás. O banco ensina a manter o quadril para trás e atingir a profundidade correta. Agache até tocar o banco levemente sem sentar e retorne.', 'quadríceps, panturrilha, glúteos, isquiotibiais, lombar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Squat_To_A_Bench/0.jpg'),
  ('Subida no Banco com Barra', 'pernas', 'intermediario', 'Em pé com a barra no trapézio atrás de uma plataforma elevada. Coloque o pé direito na plataforma e suba estendendo o quadril e joelho desse lado. Use principalmente o calcanhar para impulsionar o restante do corpo e posicione também o pé esquerdo na plataforma.', 'quadríceps, panturrilha, glúteos, isquiotibiais, quadríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Step_Ups/0.jpg'),
  ('Avanço Caminhando com Barra', 'pernas', 'iniciante', 'Em pé com a barra no trapézio e pés na largura dos ombros. Dê um passo à frente com uma perna e desça o joelho traseiro quase tocando o chão. Mantenha o torso ereto e o joelho da frente sobre o pé. Continue alternando as pernas em movimento de caminhada.', 'quadríceps, panturrilha, glúteos, isquiotibiais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Walking_Lunge/0.jpg'),
  ('Mergulho no Banco (Tríceps)', 'triceps', 'iniciante', 'Com as mãos no banco atrás de você e as pernas estendidas à frente, desça o corpo dobrando os cotovelos até aproximadamente 90 graus ou levemente abaixo. Empurre de volta à extensão completa contraindo os tríceps. Mantenha o torso próximo ao banco.', 'tríceps, peitoral, ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bench_Dips/0.jpg'),
  ('Supino Reto (Powerlifting)', 'triceps', 'avancado', 'Deite no banco com a cabeça além da barra se possível. Túque os pés por baixo e faça um arco nas costas. Use a barra para elevar os ombros do banco e retraia as escápulas. Use os pés para empurrar o trapézio contra o banco. A pegada deve cobrir o anel da barra. Execute o movimento de forma explosiva mantendo a tensão total.', 'tríceps, peitoral, antebraço, latíssimo do dorso, ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bench_Press_-_Powerlifting/0.jpg'),
  ('Supino com Elástico', 'peito', 'iniciante', 'Prenda o elástico sob a perna do banco mais próxima à cabeça. Segure as alças e deite no banco. Pressione o elástico para cima como num supino convencional. A resistência aumenta ao longo do movimento.', 'peitoral, ombros, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bench_Press_-_With_Bands/0.jpg'),
  ('Supino com Correntes', 'triceps', 'avancado', 'Ajuste as correntes e posicione-as nas extremidades da barra. Deite no banco, retraia as escápulas e faça o arco. A resistência das correntes aumenta progressivamente conforme a barra sobe.', 'tríceps, peitoral, latíssimo do dorso, ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bench_Press_with_Chains/0.jpg'),
  ('Pullover com Barra (Braços Fletidos)', 'costas', 'intermediario', 'Deite no banco plano segurando a barra acima do peito com uma leve dobra nos cotovelos. Essa é a posição inicial. Abaixe a barra em arco sobre a cabeça em direção ao chão mantendo a leve flexão dos cotovelos e retorne.', 'latíssimo do dorso, peitoral, latíssimo do dorso, ombros, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent-Arm_Barbell_Pullover/0.jpg'),
  ('Pullover com Haltere (Braços Fletidos)', 'peito', 'intermediario', 'Posicione um haltere em pé no banco. Deite perpendicular ao banco com apenas os ombros apoiados. Os quadris ficam abaixo do banco com as pernas dobradas e os pés no chão. Segure o haltere com as duas mãos acima do peito com os cotovelos levemente dobrados e abaixe-o em arco sobre a cabeça.', 'peitoral, latíssimo do dorso, ombros, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent-Arm_Dumbbell_Pullover/0.jpg'),
  ('Elevação de Quadril com Joelhos Dobrados', 'abdomen', 'iniciante', 'Deite de costas com os braços ao lado do corpo. Dobre os joelhos a aproximadamente 75 graus e eleve os pés do chão cerca de 5 cm. Esse é o ponto inicial. Contraia o abdômen inferior elevando o quadril do chão.', 'abdominais', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent-Knee_Hip_Raise/0.jpg'),
  ('Remada Curvada com Barra', 'costas', 'iniciante', 'Segure a barra com pegada pronada. Com os joelhos levemente dobrados, incline o tronco à frente mantendo as costas retas até quase paralelo ao chão. Puxe a barra em direção ao abdômen mantendo os cotovelos próximos ao corpo e retraindo as escápulas no topo.', 'dorsais médios, bíceps, latíssimo do dorso, ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_Barbell_Row/0.jpg'),
  ('Crucifixo Inverso com Halteres Apoiado', 'ombro', 'iniciante', 'Em pé com um banco inclinado à frente, incline-se até a testa tocar o banco, mantendo as costas retas e o torso paralelo ao chão. Os halteres pendentes com as palmas uma para a outra. Abra os braços lateralmente até a altura dos ombros contraindo o deltoide posterior.', 'ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_Dumbbell_Rear_Delt_Raise_With_Head_On_Bench/0.jpg'),
  ('Elevação Lateral no Cabo Baixo Curvado', 'ombro', 'iniciante', 'Selecione o peso e segure a alça da roldana baixa com a mão direita. Incline o tronco até ficar quase paralelo ao chão. As pernas levemente dobradas e a mão esquerda apoiada na coxa. O braço direito pendurado levemente dobrado. Eleve o braço lateralmente até a altura dos ombros.', 'ombros, lombar, dorsais médios, trapézio', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_Low-Pulley_Side_Lateral/0.jpg'),
  ('Remada Curvada Unilateral com Barra', 'costas', 'iniciante', 'Carregue peso em apenas uma extremidade da barra olímpica. Prenda a outra ponta no canto de duas paredes ou sob um objeto pesado. Incline o tronco até quase paralelo ao chão com os joelhos levemente dobrados. Puxe a barra com uma mão em direção ao abdômen.', 'dorsais médios, bíceps, latíssimo do dorso, lombar, trapézio', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_One-Arm_Long_Bar_Row/0.jpg'),
  ('Remada Curvada com Barra Dois Braços', 'costas', 'intermediario', 'Carregue peso em apenas uma extremidade da barra olímpica e prenda a outra ponta. Incline o tronco até quase paralelo ao chão. Puxe a barra com as duas mãos em direção ao abdômen, retraindo as escápulas no topo.', 'dorsais médios, bíceps, latíssimo do dorso', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_Two-Arm_Long_Bar_Row/0.jpg'),
  ('Remada Curvada com Dois Halteres', 'costas', 'iniciante', 'Com um haltere em cada mão (palmas voltadas para o corpo), incline o tronco à frente mantendo as costas retas. Os pesos pendurados perpendiculares ao chão. Puxe os halteres para os lados do corpo expirando e contraindo os dorsais. Retorne com controle.', 'dorsais médios, bíceps, latíssimo do dorso, ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_Two-Dumbbell_Row/0.jpg'),
  ('Remada Curvada com Halteres (Pegada Neutra)', 'costas', 'iniciante', 'Com um haltere em cada mão (palmas uma para a outra), incline o tronco à frente com as costas retas. Puxe os halteres para os lados do corpo espirando e retraindo as escápulas. A pegada neutra reduz a tensão nos ombros.', 'dorsais médios, bíceps, latíssimo do dorso', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_Two-Dumbbell_Row_With_Palms_In/0.jpg'),
  ('Bent Press', 'abdomen', 'avancado', 'Suba um kettlebell ao ombro. Incline o tronco lateralmente para o lado oposto ao kettlebell até conseguir tocar o chão com a mão livre, mantendo os olhos no kettlebell. Ao mesmo tempo, pressione o kettlebell verticalmente estendendo o cotovelo.', 'abdominais, glúteos, isquiotibiais, lombar, quadríceps, ombros, tríceps', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Press/0.jpg'),
  ('Supino com Tábua', 'triceps', 'intermediario', 'Deite no banco com a cabeça além da barra. Uma tábua é posicionada sobre o peito pelo parceiro ou presa sob a camisa, limitando o arco de movimento. Retraia as escápulas e faça o arco. Execute o supino descendo a barra até a tábua e pressionando de volta.', 'tríceps, peitoral, antebraço, latíssimo do dorso, ombros', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Board_Press/0.jpg'),
  ('Elevação Corporal (Body-Up)', 'triceps', 'intermediario', 'Assuma a posição de prancha baixa apoiado nos antebraços e pontas dos pés, mantendo o torso reto e os antebraços na largura dos ombros. Pressione firmemente as palmas no chão e estenda os cotovelos elevando o corpo. Mantenha o torso rígido durante o movimento.', 'tríceps, abdominais, antebraço', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Body-Up/0.jpg')
